import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS, ArcElement, Tooltip, Legend,
  CategoryScale, LinearScale, BarElement, Title
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [selectedPeriod, setSelectedPeriod] = useState(null);

  const fetchStats = async (period = null) => {
    const url = period !== null
      ? `/api/dashboard-stats?period=${period}`
      : "/api/dashboard-stats";
    const res = await fetch(url);
    const data = await res.json();
    setStats(data);
  };

  useEffect(() => {
  const interval = setInterval(() => {
    const now = new Date();
    const hours = now.getHours();
    const minutes = now.getMinutes();

    const timeStr = `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}`;
    const newPeriod = getCurrentPeriodIndex(timeStr); // helper you already use

    // 🛑 Don't update if it's outside class hours and no manual period selected
    if (newPeriod === -1 && selectedPeriod === -1) {
      setCurrentTime(now.toLocaleTimeString());
      setPeriodLabel("Outside Class Hours");
      return;
    }

    // ✅ Only update stats if period changes or it's valid
    if (newPeriod !== currentPeriod && selectedPeriod === -1) {
      fetchStats(); // fetch with auto-detected period
    }

    setCurrentTime(now.toLocaleTimeString());
    setCurrentPeriod(newPeriod);
    setPeriodLabel(newPeriod !== -1 ? `Period ${newPeriod + 1}` : "Outside Class Hours");
  }, 1000);

  return () => clearInterval(interval);
}, [currentPeriod, selectedPeriod]);


  if (!stats) return <div>Loading...</div>;

  const donutOptions = {
    cutout: "60%",
    plugins: {
      legend: { position: "bottom", labels: { boxWidth: 12, padding: 10 } },
      tooltip: { enabled: true },
    },
  };

  const getDonutData = (labels, values, colors) => ({
    labels,
    datasets: [{
      data: values,
      backgroundColor: colors,
      borderWidth: 0,
    }],
  });

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [{
      label: "Free Rooms",
      data: Object.values(stats.barChart),
      backgroundColor: ["#2196F3", "#8BC34A", "#FF9800", "#03A9F4", "#E91E63", "#FFC107"],
      barThickness: 30,
    }],
  };

  return (
    <div className="dashboard-container">
      <h2 className="dashboard-heading">Classroom Dashboard</h2>

      <div className="time-row">
        <div><strong>Time:</strong> {stats.time}</div>
        <div><strong>Period:</strong> {stats.periodLabel}</div>
        <div>
          <strong>Manual:</strong>{" "}
          <select
            value={selectedPeriod ?? ""}
            onChange={(e) => setSelectedPeriod(e.target.value)}
          >
            <option value="">Auto</option>
            {[...Array(8)].map((_, i) => (
              <option key={i} value={i}>Period {i + 1}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="dashboard-grid">
        <div className="card small-chart">
          <h4>Free vs Occupied</h4>
          <Doughnut
            data={getDonutData(["Occupied", "Free"], [stats.pieChart.occupied, stats.pieChart.free], ["#f44336", "#4CAF50"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Projector Rooms</h4>
          <Doughnut
            data={getDonutData(["Projectors", "Others"], [stats.resources.projectorRooms, stats.resources.totalRooms - stats.resources.projectorRooms], ["#FF9800", "#e0e0e0"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Free Labs</h4>
          <Doughnut
            data={getDonutData(["Labs", "Others"], [stats.resources.labs, stats.resources.totalRooms - stats.resources.labs], ["#9C27B0", "#e0e0e0"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Free Classrooms</h4>
          <Doughnut
            data={getDonutData(["Classrooms", "Others"], [stats.resources.classrooms, stats.resources.totalRooms - stats.resources.classrooms], ["#3F51B5", "#e0e0e0"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Not Occupied</h4>
          <Doughnut
            data={getDonutData(["Not Occupied", "Occupied"], [stats.resources.totalRooms - stats.pieChart.occupied, stats.pieChart.occupied], ["#009688", "#f44336"])}
            options={donutOptions}
          />
        </div>

        <div className="card full-width">
          <h4 style={{ marginLeft: '10px' }}>Free Rooms Per Weekday</h4>
          <div className="bar-info-container">
            <div className="bar-chart">
              <Bar
                data={barData}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  plugins: { legend: { display: false } },
                  scales: { y: { beginAtZero: true } },
                }}
              />
            </div>
            <div className="info-panel">
              <p><strong>Total rooms:</strong> {stats.resources.totalRooms}</p>
              <p><strong>Total labs:</strong> {stats.resources.labs}</p>
              <p><strong>Total free rooms:</strong> {stats.pieChart.free}</p>
              <p><strong>Total projector free:</strong> {stats.resources.projectorRooms}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
